class Solution:
    def rotateElements(self, nums, k):
        positions = [i for i, v in enumerate(nums) if v >= 0]
        vals = [nums[i] for i in positions]
        m = len(vals)
        result = list(nums)
        if m:
            steps = k % m
            for _ in range(steps):
                vals.append(vals.pop(0))
            for pos, v in zip(positions, vals):
                result[pos] = v
        return result

