class Solution:
    def rotateElements(self, nums, k):
        positions = [i for i, v in enumerate(nums) if v >= 0]
        vals = [nums[i] for i in positions]
        m = len(vals)
        result = list(nums)
        if m:
            k_mod = k % m
            rotated = vals[k_mod:] + vals[:k_mod]
            for pos, v in zip(positions, rotated):
                result[pos] = v
        return result

