var rotateElements = function(nums, k) {
    const positions = [];
    const vals = [];
    for (let i = 0; i < nums.length; i++) {
        if (nums[i] >= 0) {
            positions.push(i);
            vals.push(nums[i]);
        }
    }
    const result = nums.slice();
    const m = vals.length;
    if (m) {
        const kMod = k % m;
        const rotated = vals.slice(kMod).concat(vals.slice(0, kMod));
        for (let i = 0; i < positions.length; i++) {
            result[positions[i]] = rotated[i];
        }
    }
    return result;
};
